import{_ as t}from"./chunks/plugin-vue_export-helper.DlAUqK2U.js";import{o as a,c as s,a as n}from"./chunks/runtime-core.esm-bundler.BcSW7cUG.js";const m=JSON.parse('{"title":"GraphQL резолверы","description":"","frontmatter":{"title":"GraphQL резолверы","date":"2020-09-24T00:00:00.000Z","head":[["link",{"rel":"canonical","href":"https://alterfo.github.io/posts/2020-09-24-graphql-resolvers"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:title","content":"GraphQL резолверы"}],["meta",{"property":"og:description","content":"Oleg Sidorkin — инженер и музыкант. Проекты, инструменты и заметки."}],["meta",{"property":"og:url","content":"https://alterfo.github.io/posts/2020-09-24-graphql-resolvers"}],["meta",{"property":"og:image","content":"https://alterfo.github.io/og.png"}],["meta",{"property":"og:site_name","content":"Alterfo"}],["meta",{"property":"og:locale","content":"ru_RU"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"GraphQL резолверы"}],["meta",{"name":"twitter:description","content":"Oleg Sidorkin — инженер и музыкант. Проекты, инструменты и заметки."}],["meta",{"name":"twitter:image","content":"https://alterfo.github.io/og.png"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"BlogPosting\\",\\"headline\\":\\"GraphQL резолверы\\",\\"description\\":\\"Oleg Sidorkin — инженер и музыкант. Проекты, инструменты и заметки.\\",\\"url\\":\\"https://alterfo.github.io/posts/2020-09-24-graphql-resolvers\\",\\"inLanguage\\":\\"ru-RU\\",\\"author\\":{\\"@type\\":\\"Person\\",\\"name\\":\\"Oleg Sidorkin\\",\\"alternateName\\":\\"alterfo\\",\\"url\\":\\"https://alterfo.github.io\\",\\"jobTitle\\":\\"Software Engineer\\",\\"knowsAbout\\":[\\"Music\\",\\"Audio DSP\\",\\"AI\\",\\"RAG\\",\\"Frontend Development\\",\\"Solution Architecture\\"],\\"sameAs\\":[\\"https://github.com/alterfo\\"]},\\"datePublished\\":\\"2020-09-24\\"}"]]},"headers":[],"relativePath":"posts/2020-09-24-graphql-resolvers.md","filePath":"posts/2020-09-24-graphql-resolvers.md"}'),p={name:"posts/2020-09-24-graphql-resolvers.md"};function o(r,e,i,l,c,g){return a(),s("div",null,[...e[0]||(e[0]=[n(`<p>Да, наконец-то техническая статья 😃</p><p>Резолверы это ядро языка запросов, о котором пойдёт речь.</p><p>Сначала пара слов о том, что такое GraphQL и зачем он понадобился.</p><p>Когда микросервисы вошли в обиход любого мало-мальски серьезного проекта, собирать данные на клиенте - делая несколько запросов - стало большой болью фронтенд-разработчиков. Несмотря на то, что мы уже активно пользуемся null-safe navigation operator (?.) для предотвращения падений из-за отсутствия каких-либо данных, приходящая с сервера модель может отличаться от контрактной, да и собирать запросы в кучу через Promise.all или RxJS тоже требует особого образования и мышления.</p><p>Сначала мы ввели понятие BFF (Backend-for-Frontend) и его разновидность Backend-in-the-Frontend. Суть в том, чтобы агрегировать запросы в модели данных, необходимые клиенту, но в случае REST API, запросы все-равно имели место быть неудобными и деревянными. И нужно было пилить собственный json-schema валидатор чтобы быть уверенным что данные соответствуют контракту.</p><p>GraphQL решает эту задачу наилучшим образом, позволяя клиенту делать запросы вида:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>query Category {</span></span>
<span class="line"><span>    category(id:12) {</span></span>
<span class="line"><span>        products(limit:3) {</span></span>
<span class="line"><span>            name</span></span>
<span class="line"><span>            price</span></span>
<span class="line"><span>            photoUrl</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span>        subCategories {</span></span>
<span class="line"><span>            name</span></span>
<span class="line"><span>            photoUrl</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>Запрос при этом проходит три фазы:</p><ol><li>построение абстрактного синтаксического дерева (AST)</li><li>валидация AST на соответствие каталогу типов (schema)</li><li>исполнение резолверов полей для формирования результата в JSON-формате (автору JSON нравится когда это произносят с французским прононсом)</li></ol><p>Резолверы работают следующим образом:</p><ul><li>запросы на одном уровне дерева исполняются в параллели</li><li>если запрос асинхронный, его потомки ждут пока он &quot;зарезолвится&quot;</li><li>поскольку запросы выполняются в параллели, лучше всего если они атомарны, идемпотентны (один и тот же запрос приводит к одинаковым результатам) и без сайд-эффектов (нетоксичными 😃)</li></ul><p>Сигнатура метода резолвера проста:</p><div class="language-js vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">fieldName</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(parent, args, context, info) { result }</span></span></code></pre></div><p>Где,</p><ul><li><strong>parent —</strong> данные родительского резолвера,</li><li><strong>args —</strong> параметры, переданные в query,</li><li><strong>context —</strong> объект, который предоставлен всем резолвером, который можно менять (но не стоит), он чистится между запросами, в нём принято хранить данные аутентификации и авторизации, модели, фетчеры, данные запросов. Не стоит использовать его для кеширования</li><li><strong>info —</strong> редко используемый объект, специфичная информация для поля</li></ul><p>Необязательно создавать резолвер на каждое поле, достаточно указать корневой, остальные подставятся сами.</p><p>Несмотря на очевидное преимущество перед REST API в удобстве использования, GraphQL имеет несколько недостатков.</p><p>GraphQL не даёт делать рекурсивные запросы (надеюсь, не нужно объяснять почему, это скорее фича, а не баг), каждое вложенное поле нужно описывать явно, ограничивая дерево запросов.</p><p>В случае когда корень дерева содержит множество элементов, и вы запрашиваете поле внутри каждого из них, которое тоже является отдельным запросом, вы рискуете сделать сотни запросов. Это называется проблемой N+1. Проще говоря, это проблема &quot;batch&quot; запросов.Каждый случай индивидуален, но для решения вполне можно использовать context для кеширования промежуточных данных.</p><p>Источник вдохновения: <a href="https://medium.com/paypal-engineering/graphql-resolvers-best-practices-cd36fdbcef55" target="_blank" rel="noreferrer">https://medium.com/paypal-engineering/graphql-resolvers-best-practices-cd36fdbcef55</a></p>`,20)])])}const u=t(p,[["render",o]]);export{m as __pageData,u as default};
